import { forwardRef, useId, type ReactNode } from 'react';
import { cn } from '../../utils/cn';
import styles from './Input.module.css';

export type InputType =
  'text' | 'email' | 'password' | 'number' | 'search' | 'tel' | 'url';

export interface InputProps extends Omit<
  React.InputHTMLAttributes<HTMLInputElement>,
  'size' | 'type'
> {
  type?: InputType;
  label: string;
  helperText?: string;
  error?: string;
  leftAddon?: ReactNode;
  rightAddon?: ReactNode;
  wrapperClassName?: string;
}

export const Input = forwardRef<HTMLInputElement, InputProps>(function Input(
  {
    type = 'text',
    label,
    helperText,
    error,
    leftAddon,
    rightAddon,
    id,
    className,
    wrapperClassName,
    disabled,
    required,
    'data-testid': dataTestId = 'tatva-input',
    ...rest
  }: InputProps & { 'data-testid'?: string },
  ref,
) {
  const generatedId = useId();
  const inputId = id ?? generatedId;
  const helperId = `${inputId}-helper`;
  const errorId = `${inputId}-error`;

  const describedBy =
    [error ? errorId : undefined, helperText && !error ? helperId : undefined]
      .filter(Boolean)
      .join(' ') || undefined;

  return (
    <div className={cn(styles.wrapper, wrapperClassName)}>
      <label htmlFor={inputId} className={styles.label}>
        {label}
        {required && (
          <span className={styles.required} aria-hidden="true">
            {' *'}
          </span>
        )}
      </label>
      <div
        className={cn(
          styles.inputWrapper,
          error && styles.hasError,
          disabled && styles.disabled,
        )}
      >
        {leftAddon && <span className={styles.addon}>{leftAddon}</span>}
        <input
          ref={ref}
          id={inputId}
          type={type}
          className={cn(styles.input, className)}
          aria-invalid={error ? true : undefined}
          aria-describedby={describedBy}
          disabled={disabled}
          required={required}
          data-testid={dataTestId}
          {...rest}
        />
        {rightAddon && <span className={styles.addon}>{rightAddon}</span>}
      </div>
      {helperText && !error && (
        <span id={helperId} className={styles.helper}>
          {helperText}
        </span>
      )}
      {error && (
        <span id={errorId} className={styles.error} role="alert">
          {error}
        </span>
      )}
    </div>
  );
});

.wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--tatva-space-1);
  font-family: var(--tatva-font-family);
}

.label {
  font-size: var(--tatva-font-size-sm);
  font-weight: var(--tatva-font-weight-medium);
  color: var(--tatva-color-fg);
  line-height: var(--tatva-line-height-tight);
}

.required {
  color: var(--tatva-color-error);
}

.inputWrapper {
  display: flex;
  align-items: center;
  gap: var(--tatva-space-2);
  background-color: var(--tatva-color-bg);
  border: 1px solid var(--tatva-color-border);
  border-radius: var(--tatva-radius-md);
  padding: 0 var(--tatva-space-3);
  transition:
    border-color var(--tatva-transition-fast),
    box-shadow var(--tatva-transition-fast);
}

.inputWrapper:focus-within {
  border-color: var(--tatva-color-primary-500);
  box-shadow: 0 0 0 3px var(--tatva-color-primary-200);
}

.hasError {
  border-color: var(--tatva-color-error);
}
.hasError:focus-within {
  box-shadow: 0 0 0 3px var(--tatva-color-error-bg);
}

.disabled {
  background-color: var(--tatva-color-bg-subtle);
  opacity: 0.7;
  cursor: not-allowed;
}

.input {
  flex: 1;
  min-width: 0;
  height: 40px;
  background: transparent;
  border: none;
  outline: none;
  color: var(--tatva-color-fg);
  font-family: inherit;
  font-size: var(--tatva-font-size-md);
  line-height: var(--tatva-line-height-normal);
}

.input:disabled {
  cursor: not-allowed;
}

.input::placeholder {
  color: var(--tatva-color-fg-muted);
}

.addon {
  display: inline-flex;
  align-items: center;
  color: var(--tatva-color-fg-muted);
  font-size: var(--tatva-font-size-sm);
  line-height: 0;
}

.helper {
  font-size: var(--tatva-font-size-xs);
  color: var(--tatva-color-fg-muted);
}

.error {
  font-size: var(--tatva-font-size-xs);
  color: var(--tatva-color-error);
}
